import { betterAuth } from "better-auth";
import { genericOAuth } from "better-auth/plugins";

const parseCsv = (value: string | undefined) =>
  value
    ?.split(",")
    .map((origin) => origin.trim())
    .filter(Boolean) ?? [];

export const auth = betterAuth({
  appName: "Krakstack Site",
  trustedOrigins: parseCsv(process.env.BETTER_AUTH_TRUSTED_ORIGINS),
  advanced: {
    cookiePrefix: "krakstack-site",
  },
  account: {
    encryptOAuthTokens: true,
    storeStateStrategy: "cookie",
    storeAccountCookie: true,
  },
  session: {
    cookieCache: {
      enabled: true,
      maxAge: 60 * 60 * 24 * 7,
      strategy: "jwe",
      refreshCache: true,
    },
  },
  plugins: [
    genericOAuth({
      config: [
        {
          providerId: "krakstack-auth",
          clientId: process.env.KRAKSTACK_AUTH_CLIENT_ID!,
          clientSecret: process.env.KRAKSTACK_AUTH_CLIENT_SECRET!,
          discoveryUrl:
            process.env.VITE_KRAKSTACK_AUTH_URL +
            "/.well-known/openid-configuration",
          redirectURI:
            process.env.BETTER_AUTH_URL + "/api/auth/callback/krakstack-auth",
          scopes: ["openid", "profile", "email"],
          pkce: true,
        },
      ],
    }),
  ],
});

export type AuthSession = typeof auth.$Infer.Session;

import { apiKeyClient } from "@better-auth/api-key/client";
import { createAuthClient } from "better-auth/react";
import {
  genericOAuthClient,
  organizationClient,
  twoFactorClient,
} from "better-auth/client/plugins";

export const centralAuthBaseUrl = import.meta.env.VITE_KRAKSTACK_AUTH_URL;

export const centralAuthUrl = (path: string) =>
  new URL(path, centralAuthBaseUrl).toString();

export const centralLoginUrl = (
  callbackURL: string,
  locale: "en" | "fr" = "en",
) => {
  const url = new URL(
    `/${locale}/sign-in`,
    centralAuthBaseUrl,
  );
  url.searchParams.set("redirect", callbackURL);
  return url.toString();
};

export const authClient = createAuthClient({
  baseURL: centralAuthBaseUrl,
  fetchOptions: {
    credentials: "include",
  },
  plugins: [
    genericOAuthClient(),
    twoFactorClient({
      twoFactorPage: centralAuthUrl("/2fa"),
    }),
    organizationClient(),
    apiKeyClient(),
  ],
});

import { auth } from "@/services/auth/config";
import { createFileRoute } from "@tanstack/react-router";

export const Route = createFileRoute("/api/auth/$")({
  server: {
    handlers: {
      GET: async ({ request }: { request: Request }) => {
        return await auth.handler(request);
      },
      POST: async ({ request }: { request: Request }) => {
        return await auth.handler(request);
      },
    },
  },
});

import { Context, Effect, Layer } from "effect";
import {
  FetchHttpClient,
  HttpClient,
  HttpClientRequest,
  HttpClientResponse,
  HttpServerRequest,
} from "effect/unstable/http";
import { HttpApiError } from "effect/unstable/httpapi";

import { auth } from "@/services/auth/config";

import { VerifyApiKeyPayload, VerifyApiKeyResponse } from "./schema";

const internalServerError = () => new HttpApiError.InternalServerError({});

const authBaseUrl = () => {
  const value =
    process.env.KRAKSTACK_AUTH_URL ?? process.env.VITE_KRAKSTACK_AUTH_URL;

  if (!value) {
    throw new Error("KRAKSTACK_AUTH_URL is not configured");
  }

  return value.replace(/\/$/, "");
};

export class Auth extends Context.Service<Auth>()("Auth", {
  make: Effect.gen(function* () {
    const http = yield* HttpClient.HttpClient;

    const getSession = Effect.fn("Auth.getSession")(function* () {
      const request = yield* HttpServerRequest.HttpServerRequest;
      const session = yield* Effect.tryPromise({
        try: () =>
          auth.api.getSession({ headers: new Headers(request.headers) }),
        catch: internalServerError,
      });
      return session;
    });

    const requireUser = Effect.fn("Auth.requireUser")(function* () {
      const session = yield* getSession();
      if (!session) {
        return yield* new HttpApiError.Unauthorized({});
      }
      return {
        id: session.user.id,
        name: session.user.name,
        email: session.user.email,
      };
    });

    const verifyApiKey = Effect.fn("Auth.verifyApiKey")(function* (
      payload: VerifyApiKeyPayload,
    ) {
      return yield* HttpClientRequest.post(
        `${authBaseUrl()}/api/auth/verify-api-key`,
      ).pipe(
        HttpClientRequest.bodyJson(payload),
        Effect.flatMap((request) => http.execute(request)),
        Effect.flatMap(HttpClientResponse.filterStatusOk),
        Effect.flatMap(HttpClientResponse.schemaBodyJson(VerifyApiKeyResponse)),
        Effect.mapError(internalServerError),
      );
    });

    return { getSession, requireUser, verifyApiKey };
  }),
}) {
  static readonly layer = Layer.effect(this, this.make).pipe(
    Layer.provide(FetchHttpClient.layer),
  );
}

import { Schema } from "effect";

export const ApiKeyConfigId = Schema.Union([
  Schema.Literal("user"),
  Schema.Literal("organization"),
]).annotate({
  identifier: "ApiKeyConfigId",
  title: "API key configuration ID",
  description: "The configured API key owner type to verify against.",
  examples: ["user"],
});

export const ApiKeyPermissions = Schema.Record(
  Schema.String,
  Schema.Array(Schema.String),
).annotate({
  identifier: "ApiKeyPermissions",
  title: "API key permissions",
  description: "Resource/action permissions required for API key verification.",
  examples: [{ projects: ["read"] }],
});

export const VerifyApiKeyPayload = Schema.Struct({
  key: Schema.NonEmptyString,
  configId: Schema.optional(ApiKeyConfigId),
  permissions: Schema.optional(ApiKeyPermissions),
}).annotate({
  identifier: "VerifyApiKeyPayload",
  title: "Verify API key payload",
  description: "Payload used to verify a KrakStack API key remotely.",
  examples: [
    {
      key: "user_1234567890",
      configId: "user",
      permissions: { projects: ["read"] },
    },
  ],
});

export const ApiKeyVerificationError = Schema.Struct({
  message: Schema.String,
  code: Schema.String,
}).annotate({
  identifier: "ApiKeyVerificationError",
  title: "API key verification error",
  description: "Structured reason returned when an API key is invalid.",
  examples: [{ message: "API key is invalid", code: "INVALID_API_KEY" }],
});

export const VerifiedApiKey = Schema.Struct({
  id: Schema.String,
  configId: Schema.String,
  name: Schema.NullOr(Schema.String),
  start: Schema.NullOr(Schema.String),
  prefix: Schema.NullOr(Schema.String),
  referenceId: Schema.String,
  enabled: Schema.NullOr(Schema.Boolean),
  expiresAt: Schema.NullOr(Schema.DateFromString),
  createdAt: Schema.DateFromString,
  updatedAt: Schema.DateFromString,
  permissions: Schema.NullOr(ApiKeyPermissions),
  metadata: Schema.NullOr(Schema.Unknown),
}).annotate({
  identifier: "VerifiedApiKey",
  title: "Verified API key metadata",
  description: "Non-secret metadata for a verified API key.",
  examples: [
    {
      id: "api-key-id",
      configId: "user",
      name: "Production key",
      start: "user_1234",
      prefix: "user_",
      referenceId: "user-id",
      enabled: true,
      expiresAt: null,
      createdAt: new Date("2026-01-01T00:00:00.000Z"),
      updatedAt: new Date("2026-01-01T00:00:00.000Z"),
      permissions: { projects: ["read"] },
      metadata: null,
    },
  ],
});

export const VerifyApiKeyResponse = Schema.Struct({
  valid: Schema.Boolean,
  error: Schema.NullOr(ApiKeyVerificationError),
  key: Schema.NullOr(VerifiedApiKey),
}).annotate({
  identifier: "VerifyApiKeyResponse",
  title: "Verify API key response",
  description: "Result of verifying a remote API key.",
  examples: [
    {
      valid: true,
      error: null,
      key: {
        id: "api-key-id",
        configId: "user",
        name: "Production key",
        start: "user_1234",
        prefix: "user_",
        referenceId: "user-id",
        enabled: true,
        expiresAt: null,
        createdAt: new Date("2026-01-01T00:00:00.000Z"),
        updatedAt: new Date("2026-01-01T00:00:00.000Z"),
        permissions: { projects: ["read"] },
        metadata: null,
      },
    },
  ],
});

export type VerifyApiKeyPayload = typeof VerifyApiKeyPayload.Type;
export type VerifyApiKeyResponse = typeof VerifyApiKeyResponse.Type;

import { Context, Effect, Layer, Schema } from "effect";
import { HttpApiMiddleware } from "effect/unstable/httpapi";

import { Auth } from "@/services/auth";

export class CurrentUser extends Context.Service<
  CurrentUser,
  {
    id: string;
    name: string;
    email: string;
  }
>()("site/CurrentUser") {}

export class Unauthorized extends Schema.TaggedErrorClass<Unauthorized>()(
  "Unauthorized",
  {
    message: Schema.String,
  },
  { httpApiStatus: 401 },
) {}

export class AuthMiddleware extends HttpApiMiddleware.Service<
  AuthMiddleware,
  {
    provides: CurrentUser;
  }
>()("site/AuthMiddleware", {
  error: Unauthorized,
}) {}

export const AuthMiddlewareLive = Layer.effect(
  AuthMiddleware,
  Effect.gen(function* () {
    const authService = yield* Auth;
    return (httpEffect) =>
      Effect.gen(function* () {
        const user = yield* authService
          .requireUser()
          .pipe(
            Effect.mapError(
              () => new Unauthorized({ message: "Authentication required" }),
            ),
          );
        return yield* Effect.provideService(httpEffect, CurrentUser, user);
      });
  }),
).pipe(Layer.provide(Auth.layer));

